 var captureCtvPerPin = (ICaptureCtvPerPinTest)this.FunctionalTest;
 var dtsPinCtvData = new Dictionary<string, string>();
   foreach (var pinName in this.dtsHandler.GetPinNames())
{
   dtsPinCtvData.Add(pinName, captureCtvPerPin.GetCtvData(pinName));
}
dtsHandler.ProcessDtsMeasurementsFromCtvData(dtsPinCtvData);
